CREATE INDEX idx_nodes_parent ON nodes(parent_uuid, rank);
CREATE INDEX idx_nodes_dirty ON nodes(dirty);
CREATE TABLE wf_mirrors
			(
				node_uuid text PRIMARY KEY,
				wf_id text NOT NULL,
				anchor text NOT NULL DEFAULT '',
